'use client';

import { useEffect, useRef } from 'react';
import gsap from 'gsap';

export default function DotMatrixBackground() {
  const glowRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let animationFrameId: number;
    let currentX = window.innerWidth / 2;
    let currentY = window.innerHeight / 2;
    let targetX = currentX;
    let targetY = currentY;

    const onMouseMove = (e: MouseEvent) => {
      targetX = e.clientX;
      targetY = e.clientY;
    };

    window.addEventListener('mousemove', onMouseMove);

    const animate = () => {
      // Smooth interpolation
      currentX += (targetX - currentX) * 0.1;
      currentY += (targetY - currentY) * 0.1;

      if (glowRef.current) {
        glowRef.current.style.transform = `translate(${currentX}px, ${currentY}px)`;
      }

      animationFrameId = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 -z-50 bg-[#000000] overflow-hidden">
      {/* Base Dark Grid */}
      <div 
        className="absolute inset-0 opacity-10"
        style={{
          backgroundImage: 'radial-gradient(circle at 1px 1px, #ffffff 1px, transparent 1px)',
          backgroundSize: '32px 32px'
        }}
      />
      
      {/* Illuminated Grid Layer */}
      <div 
        className="absolute inset-0 mix-blend-screen opacity-60"
        style={{
          backgroundImage: 'radial-gradient(circle at 1px 1px, #cf311d 1.5px, transparent 1px)',
          backgroundSize: '32px 32px',
          maskImage: 'radial-gradient(400px circle at center, white, transparent)',
          WebkitMaskImage: 'radial-gradient(400px circle at center, white, transparent)',
          maskRepeat: 'no-repeat',
          WebkitMaskRepeat: 'no-repeat',
          maskPosition: 'calc(var(--mouse-x, 50vw) - 400px) calc(var(--mouse-y, 50vh) - 400px)',
          WebkitMaskPosition: '0 0', // Overridden by transform
        }}
      >
          {/* Tracking Glow Object */}
          <div 
            ref={glowRef}
            className="absolute top-0 left-0 w-[800px] h-[800px] -ml-[400px] -mt-[400px] pointer-events-none"
            style={{
                background: 'radial-gradient(circle 400px at center, rgba(207,49,29,1) 0%, rgba(207,49,29,0) 100%)',
                mixBlendMode: 'screen'
            }}
          />
      </div>
    </div>
  );
}
